const Q_GEOGRAPHY_2000=[{"id": "objective>Geography>2000>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The feature marked X is best described as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">col </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gap </div>", "<div style=\"font-family:Cambria;font-size:17px;\">path </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a lowland between two highlands that has a line of communication.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2000>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Tap is visible from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enso </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nino </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ned </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">They are both almost at the same altitude and the same direction along a gentle slope.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2000>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Roads and settlements are restricted in the area because of the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">steep hill slopes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">present of many rivers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">predominance of footpaths </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The area is covered with rugged hills. Roads and settlements are restricted in the area because of the steep hill slopes.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2000>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The bearing of the end of the secondary school road at the Ned from the road junction at Gag is approximately </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">170<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">260<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">350<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using a protractor to measure at Gag, you will get approximately 350<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2000>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The approximate elevation of the spot height indicated on the eastern peak is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">725m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">715m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">710m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">695m </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The approximate elevation of the spot height indicated on the eastern peak is about 710m.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2000>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The technique that would produce the most accurate contoured map of a small area is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prismatic compass survey </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lands-use survey </div>", "<div style=\"font-family:Cambria;font-size:17px;\">plane-table survey </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chain survey </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A compass is used to survey a small area. The technique that would produce the most accurate contoured map of a small area is prismatic compass survey.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2000>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the histogram below to answer this question. <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The modal temperature for the town is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">29<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From 4 different months of June, July, October and December, the modal temperature is 23°.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2000>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the histogram below to answer this question. <br/> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The annual range of temperature for the town is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">23<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The highest temperature is 30° and the lowest is 23°. The range will be (30 - 23)° = 7 °.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2000>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A direct natural consequence of drought is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">famine and starvation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high mortality rate in livestock </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drying up of most water sources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">changes in the chemical properties of soils </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A long period of absence of water supply/rainfall/precipitation causes all water sources to dry off which can eventually result in famine.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2000>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The feature is a product of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glacial erosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind abration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water erosion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind deposition </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wind bearing particles blast the rock surface in the desert to wear it away.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2000>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The landform is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">yardang </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zeugen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mesa and butte </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rock pedestal </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It consist of alternate layers of hard & soft rocks which are arranged horizontally.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2000>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common tree in the desert is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">date </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acacia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">larch </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most common tree in the desert is the Acacia. Acacia trees are well adapted to desert conditions, they have long roots that can reach deep water sources, thick bark to resist fire, and small, waxy leaves to reduce water loss.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2000>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most obvious physical feature that distinguishes undisturbed mature soil from an imature soil is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">humus content </div>", "<div style=\"font-family:Cambria;font-size:17px;\">layered profile </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nutrient status </div>", "<div style=\"font-family:Cambria;font-size:17px;\">topsoil texture </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most obvious physical feature that distinguishes undisturbed mature soil from immature soil is the layered profile. Mature soils have a clear layered structure, with a topsoil layer rich in organic matter, a subsoil layer where minerals are leached down from the topsoil, and a parent material layer which is the original rock material that the soil formed from.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2000>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The direction of flow of ocean currents is determined mainly by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rotation of the earth and land and sea breeze </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shape of the continents and the temperature of the continental interior </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevailing winds and the rotation of the earth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">depth of the ocean and the amount of fresh water inflow </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Earth rotation deflects ocean to the right in the northern hemisphere and to the left in the southern hemisphere.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2000>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The medium class of layered cloud which brings continuous rain, snow or sleet is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">altocumulus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">altostratus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stratocumulus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nimbostratus </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nimbostratus clouds are a type of cloud that cover the sky in a dark gray layer. They are thick enough to block out the sun and are often associated with continuous rain, snow, or sleet. Therefore, the correct answer is nimbostratus.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2000>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The biodiversity of an ecosystem may be reduced through the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">extinction of plant species </div>", "<div style=\"font-family:Cambria;font-size:17px;\">removal of single animal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduction of new plant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trapping of a single fish </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Biodiversity refers to the variety of life in a particular habitat or ecosystem. It can be reduced through the extinction of plant species. When a species goes extinct, it can disrupt the food chain and lead to a decrease in biodiversity. Therefore, the correct answer is the extinction of plant species.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2000>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A soft, black opaque carbonaceous rock that can be used to make pencil is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lignite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">graphite </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Graphite is a soft, black, crystalline form of carbon that is used for making pencils. It is opaque and has a metallic luster. Therefore, the correct answer is graphite.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2000>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vegetation that is characterized by tall trees, climbing plants and creepers in the Amazon is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pampas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">veldt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">selvas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">steppes </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vegetation characterized by tall trees, climbing plants, and creepers in the Amazon is called 'selvas'. This term is used to describe the dense, tropical rainforest that is found in the Amazon Basin. The other options, pampas, veldt, and steppes, refer to different types of grasslands, not rainforests.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2000>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One predominantly temperate grain that is being cultivated in some tropical areas today is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sorghum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">barley </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maize </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wheat </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maize and Sorghum are predominant in the tropics while barley and wheat are for temperate regions but wheat is becoming more adaptable to the tropics.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2000>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scientist who propounded the theory of continental drift was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Alfred Wegener </div>", "<div style=\"font-family:Cambria;font-size:17px;\">William Davis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Arthur Holmes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Francis Bacon </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He propounded the theory of how the super continent is divided into various lands.  <br/>  Continental drift is the movement of the Earth's continents relative to each other, thus appearing to drift across the ocean bed. The speculation that continents might have 'drifted' was first put forward by Abraham Ortelius in 1596. The concept was independently and more fully developed by Alfred Wegener in 1912.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2000>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A sedimentary formed only in sea and oceans in warm tropical and subtropical environments is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandstone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mudstone </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Forms at the bottom of water bodies like oceans and seas, especially in quiet places.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2000>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Exfoliation and rock disintegration are wealthering processes mostly found in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tundra region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">savannah region  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">desert region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mediterranian region  </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Exfoliation occurs when a rock surface is exposed to heat in the day and cold at night. This is a characteristic of desert weather.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2000>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An area of the world that is likely to have 24-hour sunshine on July of any year is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Horse latitudes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Southern polar area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equatorial area </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Northern polar area </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At that season of the year, places north of tropic of cancer experience increase in hours of daylight, northward.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2000>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Where winds are onshore, warm ocean currents will bring a type of condition to the coastland that is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cool and dry </div>", "<div style=\"font-family:Cambria;font-size:17px;\">warm and wet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cool and wet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hot and dry </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is warm because the current is warm and wet due to the fact that current picks up water as it flows over the seas & drops it as it rains on the continent.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2000>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of the wind is usually measured by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an anemometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">speedometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an arrow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a wind vane </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The speed of the wind is measured using an instrument called an anemometer. A speedometer is used to measure the speed of a vehicle, an arrow is a projectile, and a wind vane is used to determine the direction of the wind, not its speed. Therefore, the correct answer is 'an anemometer'.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2000>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Acid lava is rich in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnesium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">silica </div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Acid lava is high in silica content. Silica is a compound made of silicon and oxygen and is the most abundant compound in the Earth's crust. Acid lava is known for its high viscosity due to its high silica content. Therefore, the correct answer is 'silica'.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2000>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The live commentary of a football match which started at 4.00 pm, at a place on longitude 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>E will be received by a listener in a town on longitude 160<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>W at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.20 pm, same day </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.20 a.m, same day</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.40 am, next day</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.40 a.m, next day </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Longitudinal difference = 160°W + 15°E = 175°  <br/>  Since 15° = 1 hour, 175/15 = 11 hours 40 minutes.  <br/>  If it is at 4pm at 15° E, then it will be [4pm or (16:00) - 11:40]hours at 16°W = 4:20a.m same day.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2000>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During winter, Eskimos live in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tents </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tunnels </div>", "<div style=\"font-family:Cambria;font-size:17px;\">caves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">igloos </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Eskimos are found near the north pole. They live in Igloos in winter and in tents made from animal skin during summer.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2000>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Johannesburg, Jos and Galhivare are similar in that they all </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">act as nodal towns </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have populations of over a million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">grew because of the presence of minerals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acts as commercial centres </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">These places developed due to the discovery of mineral e.g Gold in Johannesburg and Tin & Columbite in Jos.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2000>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shaduf method of irrigation was practiced in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Egypt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Early civilization took place in Egypt with the main focus on land cultivation by irrigation near the River Nile.</div>", "topic": "REGIONAL GEOGRAPHY : IRRIGATION AGRICULTURE IN THE NILE AND NIGER BASIN"}, {"id": "objective>Geography>2000>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dairy farming is most notable in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Egypt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Denmark </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">China </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Denmark is known for its high-quality dairy products and is one of the leading exporters of dairy products in the world.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2000>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The least of the factors to be considered in the allocation of industries is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raw materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transport </div>", "<div style=\"font-family:Cambria;font-size:17px;\">markets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">climate </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">While climate can have an impact on certain industries, it is generally not as important as factors such as the availability of raw materials, transport infrastructure, and markets.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2000>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rise in the population of an area can be measured easily by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">multiplying the natural increase by the net migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">subtracting the natural increase from the net migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding the natural increase to the net migration  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dividing the natural increase by the net migration </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When excess of birth over death per year is added to the balance of immigration and emigration, it indicates population increase for the year.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2000>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Transportation is an important economic activity because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promotes diffusion of innovation and ideas </div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitates urban-rural migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotes the health national population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">help to achieve economic independence </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transportation is an important economic activity because it promotes diffusion of innovation and ideas. This is because transportation allows for the movement of goods, services, and ideas from one place to another. This movement can lead to the spread of new technologies, business practices, and cultural ideas, which can stimulate economic growth and development.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2000>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these sets enhances nucleation of rural settlement?  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Several sources of water and wet points </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Narrow valleys and rugged highlands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fertile broad plains and natural harbours</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dissected plains and wet intersections. </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nucleation of rural settlement is enhanced by 'Fertile broad plains and natural harbours'. Nucleation in geography refers to the process of forming a nucleus or core around which a settlement develops. Fertile broad plains provide ample space and resources for agriculture, which is a primary economic activity in rural areas. Natural harbours provide access to water resources and opportunities for fishing and trade, which can also attract settlement.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2000>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of a group of people from a village to an irrigation project area may be described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">urban-urban migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-urban migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">urban-rural migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rural-rural migration </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of a group of people from a village to an irrigation project area is described as rural-rural migration. This is because both the village and the irrigation project area are in rural settings. Urban-rural migration would imply movement from a city to a rural area, while rural-urban migration would be the opposite. Urban-urban migration would involve moving from one city to another.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2000>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factors influencing the distribution of population in the world are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">climate, relief, soils and mineral resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">climate, industrial activities, soil and tourism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">climate, soils, agricultural and cultural activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">relief, industrial activities, agriculture and mineral resources </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important factors influencing the distribution of population in the world are climate, relief, soils and mineral resources. Climate affects the types of activities that can be carried out in a region, and thus the number of people it can support. Relief, or the physical features of the land, can also affect population distribution, as some areas may be more habitable than others. Soils influence the types of crops that can be grown, and thus the agricultural potential of a region. Mineral resources can attract industries and thus people to a region.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2000>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most dreaded pest in the Cotton Belt of the U.S.A is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">weaver bird </div>", "<div style=\"font-family:Cambria;font-size:17px;\">beetle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">boll-weevil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">white ant </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It can spread so rapidly that in a season, a pair can multiply to 10 million. It was responsible for cotton belt migration Westward in the 17th century.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2000>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Benguela current is to Namibia what the Canaries current is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Kenya </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Angola </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mozambique </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mauritania </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Benguela Current is responsible for Namib desert in Namibia and Canary Current is responsible for the Sahara desert in Mauritania.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2000>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two prominent highlands at the Nigeria-Cameroun border are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mambila and Oban </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mandara and Alantika </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Udi and Shebshi </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos Plateau and Kukuruku </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two prominent highlands at the Nigeria-Cameroon border are the Mandara and Alantika mountains. The Mandara mountains are a volcanic range extending about 200 km along the northern part of the Cameroon-Nigeria border, while the Alantika mountains are an extension of the Adamawa Plateau in northeastern Nigeria and northern Cameroon.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2000>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important mineral deposit in South Africa which has attracted a large number of white settlers is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">iron in Durban </div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper in Cape Town </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gold in Witwatersrand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium in in Johannesburg </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South Africa is known for its significant gold deposits, particularly in the Witwatersrand region. The Witwatersrand Gold Rush in the late 19th century led to a large influx of white settlers in the region. Therefore, an important mineral deposit in South Africa which has attracted a large number of white settlers is gold in Witwatersrand.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2000>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prosperity of Kenya depends upon the cultivation of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coffee, sisal and rice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coffee, cocoa and rice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coffee, rubber and maize </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coffee, maize and sisal </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">These are crops that are grown in upland areas. The prosperity of Kenya depends upon the cultivation of coffee, maize and sisal</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2000>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major feature of manufacturing in West Africa is that the industries  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">are evenly spread over major towns </div>", "<div style=\"font-family:Cambria;font-size:17px;\">produce mainly for domestic market  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">are capital intensive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have wide market for heir products </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing industries in West Africa primarily produce for the domestic market. This is due to several factors including the high cost of exporting, lack of access to international markets, and the need to meet local demand for goods.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2000>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important air masses which affects the climate of Nigeria are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tropical maritime and tropical sea and land breezes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical maritime and the equatorial westerlies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical maritime and the tropical continental </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropical maritime and the polar continental </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The climate of Nigeria is significantly influenced by two main air masses: the tropical maritime and the tropical continental. The tropical maritime air mass brings in moisture from the Atlantic Ocean, causing the rainy season, while the tropical continental air mass is dry and comes from the Sahara Desert, causing the dry season.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2000>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The low rainfall along Cape Three Points in Ghana is due to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">upwelling of cold water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sparse vegetation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevalence of south west winds </div>", "<div style=\"font-family:Cambria;font-size:17px;\">upwelling warm water </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The low rainfall along Cape Three Points in Ghana is due to the prevalence of south west winds. </div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2000>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, continentality poses the greatest hinderance to economic development in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Niger Delta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Niger-Benue Trough </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cross River Basin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chad Basin </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, continentality poses the greatest hindrance to economic development in the Chad Basin. Continentality refers to the climatic condition of being far from the moderating influence of the sea, leading to greater temperature extremes. The Chad Basin, being located in the interior of the country and far from the sea, experiences extreme temperature variations which can hinder economic activities such as agriculture.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2000>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the dominant trees of the Guinea Savannah include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Isoberlinia, obeche and locust bean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Isoberlina, shea butter and silk cotton </div>", "<div style=\"font-family:Cambria;font-size:17px;\">acacia, dum palm and silk cotton </div>", "<div style=\"font-family:Cambria;font-size:17px;\">locust bean, oil bean and acacia </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the dominant trees of the Guinea Savannah include Isoberlinia, shea butter and silk cotton. The Guinea Savannah is a tropical grassland biome with a wet and dry climate, and these tree species are well adapted to these conditions. Isoberlinia is a genus of legume in the family Fabaceae, shea butter tree produces nuts that are used to make shea butter, a common ingredient in skin care products, and silk cotton tree is known for its large fruits filled with silky fibers.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2000>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">From its source to its mouth, the River Niger passes through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mali, Guinea, Niger and Nigeria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea, Mali, Togo and Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Guinea, Mali, Niger and Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mali, Niger, Guinea and Nigeria</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The River Niger is the third-longest river in Africa, exceeded only by the Nile and the Congo River (also known as the Zaire River). It runs in a crescent through Guinea, Mali, Niger and Nigeria before discharging through a massive delta, known as the Niger Delta of the Oil Rivers, into the Gulf of Guinea in the Atlantic Ocean. Therefore, the correct answer is 'Guinea, Mali, Niger and Nigeria'.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2000>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An environmental hazard which occurs slowly and unnoticed in the oil-producing region of the Niger Delta of Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">erosion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pollution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">flood </div>", "<div style=\"font-family:Cambria;font-size:17px;\">subsidence </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Niger Delta region of Nigeria is known for its oil production. The extraction and production of oil in this region have led to significant environmental pollution, including water, air and soil pollution. This pollution occurs slowly and often goes unnoticed until the effects are severe. Therefore, the correct answer is 'pollotion'.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2000>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One basic mineral that is common to Sokoto, Ewekoro, Calaba and Nkalagu is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">coal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marble </div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gypsum </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sokoto, Ewekoro, Calaba and Nkalagu are all known for their limestone deposits. Limestone is a basic mineral used in the production of cement. Therefore, the correct answer is 'limestone'.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}];
